const allData = $("Credilus Request").first().json.data;
const emails = allData[0].EMAILS;

function parseEmailList(emailString) {
  if (emailString) {
        return emailString
        .split(',')
        .map(email => email.trim())
        .filter(email => email !== '');
  }
}

return {
  "emails": parseEmailList(emails)
}

